--
-- Table structure for table `pm_bank_payment_record`
--

DROP TABLE IF EXISTS `pm_bank_payment_record`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pm_bank_payment_record` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `task_id` bigint NOT NULL COMMENT '任务ID',
  `document_code` varchar(64) NOT NULL COMMENT '单据编码',
  `company_bank_account_id` bigint DEFAULT NULL COMMENT '公司银行账户ID',
  `bank_provider` varchar(64) NOT NULL COMMENT '银行提供方',
  `bank_channel` varchar(64) NOT NULL COMMENT '银行支付渠道',
  `manual_paid` tinyint NOT NULL DEFAULT '0' COMMENT '是否人工标记付款:1是 0否',
  `push_request_no` varchar(128) DEFAULT NULL COMMENT '推送请求号',
  `bank_order_no` varchar(128) DEFAULT NULL COMMENT '银行订单号',
  `bank_flow_no` varchar(128) DEFAULT NULL COMMENT '银行流水号',
  `push_payload_json` longtext COMMENT '推送请求载荷JSON',
  `push_result_json` longtext COMMENT '推送结果JSON',
  `callback_payload_json` longtext COMMENT '回调载荷JSON',
  `callback_received_at` datetime DEFAULT NULL COMMENT '回调接收时间',
  `paid_at` datetime DEFAULT NULL COMMENT '付款时间',
  `receipt_status` varchar(64) DEFAULT NULL COMMENT '回单状态',
  `receipt_received_at` datetime DEFAULT NULL COMMENT '回单接收时间',
  `last_receipt_query_at` datetime DEFAULT NULL COMMENT '最近回单查询时间',
  `receipt_query_count` int NOT NULL DEFAULT '0' COMMENT '回单查询次数',
  `receipt_attachment_id` varchar(64) DEFAULT NULL COMMENT '回单附件ID',
  `receipt_file_name` varchar(255) DEFAULT NULL COMMENT '回单文件名',
  `receipt_result_json` longtext COMMENT '回单结果JSON',
  `last_error_message` varchar(1000) DEFAULT NULL COMMENT '最近错误信息',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_pm_bank_payment_record_task` (`task_id`),
  KEY `idx_pm_bank_payment_record_document` (`document_code`),
  KEY `idx_pm_bank_payment_record_account` (`company_bank_account_id`),
  KEY `idx_pm_bank_payment_record_receipt` (`receipt_status`,`manual_paid`),
  CONSTRAINT `fk_pm_bank_payment_record_account` FOREIGN KEY (`company_bank_account_id`) REFERENCES `sys_company_bank_account` (`id`),
  CONSTRAINT `fk_pm_bank_payment_record_document` FOREIGN KEY (`document_code`) REFERENCES `pm_document_instance` (`document_code`),
  CONSTRAINT `fk_pm_bank_payment_record_task` FOREIGN KEY (`task_id`) REFERENCES `pm_document_task` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='银行付款跟踪记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `pm_bank_payment_record`
--

LOCK TABLES `pm_bank_payment_record` WRITE;
/*!40000 ALTER TABLE `pm_bank_payment_record` DISABLE KEYS */;
/*!40000 ALTER TABLE `pm_bank_payment_record` ENABLE KEYS */;
UNLOCK TABLES;

